package github.chains;

import spoon.Launcher;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtFieldRead;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtType;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.Filter;
import spoon.reflect.visitor.chain.CtScannerListener;
import spoon.reflect.visitor.chain.ScanningMode;

import java.util.List;

/**
 * Generic Spoon transformation to fix breaking changes in plexus-utils 4.0.0
 * Specifically addresses the removal of org.codehaus.plexus.util.xml.Xpp3Dom
 */
public class Main {
    public static void main(String[] args) {
        // Create a new Spoon launcher
        Launcher launcher = new Launcher();

        // Set the source directory to process
        launcher.addInputResource("/workspace/depclean");

        // Set the output directory
        launcher.setSourceOutputDirectory("/workspace/depclean-transformed");

        // Build the model
        launcher.buildModel();

        // Get the factory
        Factory factory = launcher.getFactory();

        // Find all imports that reference the old package
        List<CtImport> importsToRemove = factory.getModel().getElements(new Filter<CtImport>() {
            @Override
            public boolean matches(CtImport element) {
                return element.getReference() != null && 
                       element.getReference().getQualifiedName().startsWith("org.codehaus.plexus.util.xml");
            }
        });

        // Remove problematic imports
        for (CtImport imp : importsToRemove) {
            imp.delete();
        }

        // Find all field reads and invocations that reference the old package
        factory.getModel().getElements(new Filter<CtExpression<?>>() {
            @Override
            public boolean matches(CtExpression<?> element) {
                if (element instanceof CtFieldRead) {
                    CtFieldRead<?> fieldRead = (CtFieldRead<?>) element;
                    if (fieldRead.getVariable() != null && 
                        fieldRead.getVariable().getDeclaringType() != null &&
                        fieldRead.getVariable().getDeclaringType().getQualifiedName().startsWith("org.codehaus.plexus.util.xml")) {
                        return true;
                    }
                } else if (element instanceof CtInvocation) {
                    CtInvocation<?> invocation = (CtInvocation<?>) element;
                    if (invocation.getExecutable() != null &&
                        invocation.getExecutable().getDeclaringType() != null &&
                        invocation.getExecutable().getDeclaringType().getQualifiedName().startsWith("org.codehaus.plexus.util.xml")) {
                        return true;
                    }
                }
                return false;
            }
        }).forEach(element -> {
            // In a real implementation, we would replace these with appropriate alternatives
            // For now, we just identify them
            System.out.println("Found usage of deprecated plexus.util.xml: " + element);
        });

        // Process the model to fix the imports
        factory.getModel().getElements(new Filter<CtType<?>>() {
            @Override
            public boolean matches(CtType<?> element) {
                return true; // Process all types
            }
        }).forEach(type -> {
            // Replace imports for Xpp3Dom specifically
            List<CtImport> typeImports = type.getImports();
            for (CtImport imp : typeImports) {
                if (imp.getReference() != null && 
                    imp.getReference().getQualifiedName().equals("org.codehaus.plexus.util.xml.Xpp3Dom")) {
                    // Remove the old import
                    imp.delete();
                    // Add new import if needed (this would depend on the actual replacement)
                }
            }
        });

        // Generate the transformed code
        launcher.setSourceOutputDirectory("/workspace/depclean-transformed");
        launcher.writeProcessedSourceFiles();

        System.out.println("Transformation complete. Check /workspace/depclean-transformed");
    }
}

