package github.chains;

import spoon.Launcher;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtType;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.io.File;

/**
 * Generic Spoon transformation to fix breaking changes in plexus-utils 4.0.0
 * Specifically addresses the removal of org.codehaus.plexus.util.xml.Xpp3Dom
 */
public class Main {
    public static void main(String[] args) {
        // Create a new Spoon launcher
        Launcher launcher = new Launcher();

        // Set the source directory to process - this should be configurable
        String sourceDirectory = args.length > 0 ? args[0] : "/workspace/depclean";
        String outputDirectory = args.length > 1 ? args[1] : "/workspace/depclean-transformed";

        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(outputDirectory);

        // Build the model
        launcher.buildModel();

        // Get the factory
        Factory factory = launcher.getFactory();

        // Find and remove imports that reference the problematic package
        factory.getModel().getElements(new TypeFilter<CtImport>(CtImport.class)) 
            .stream()
            .filter(imp -> {
                CtTypeReference<?> ref = imp.getReference();
                return ref != null && ref.getQualifiedName().startsWith("org.codehaus.plexus.util.xml");
            })
            .forEach(CtImport::delete);

        // Find all types that might use the old API and show them
        factory.getModel().getElements(new TypeFilter<CtType<?>>(CtType.class))
            .forEach(type -> {
                // Print the type name for reference
                System.out.println("Processing type: " + type.getQualifiedName());
            });

        // Generate the transformed code
        launcher.setSourceOutputDirectory(outputDirectory);
        launcher.writeProcessedSourceFiles();

        System.out.println("Transformation complete. Check " + outputDirectory);
    }
}

